// Dev/demo seed — "Spotlight Academy", a four-class online-learning catalog
// (music, food, technology, sports). Idempotent (fixed ids + upserts with FULL
// update payloads, so a plain re-run restores every seeded row to spec; admin
// edits to seeded rows are intentionally reverted).
//
// ORIGINAL CONTENT ONLY. This catalog is what prospective clients are shown
// when they evaluate the product, so nothing in it may reference — or depend on
// — a real person, a real brand, or another platform's media. Everything here
// is written for this seed; every image is generated by assets/generate-demo-art.ts
// and served from this instance's own /media route. Do not reintroduce hotlinked
// art or third-party sample media: an earlier revision shipped masterclass.com
// course images, picsum.photos photographs (real photographers' work) and a
// named creator's Vimeo film, which is exactly what this catalog exists to avoid.
//
// Destructive mode: SEED_WIPE=1 wipes ALL content tables (and the upload
// dirs on disk) before seeding. The wipe NEVER touches:
//   - Admin            (admin@example.com — the only way into the admin)
//   - Setting          (encrypted Stripe/PayPal/email creds + provider —
//                       cannot be re-derived; paired with SETTINGS_ENC_KEY)
//   - _prisma_migrations
// NEVER run `prisma migrate reset` against this database — it drops those too.
//
//   SEED_WIPE=1 npm run seed -w @lms/db   # wipe + reseed (the only destructive path)
//   npm run seed -w @lms/db               # plain idempotent refresh (migrate-dev safe)
//
// Provisioned instances (deploy/instance compose, driven by the control-plane
// provisioner) run this SAME seed on every container start, parameterized:
//   SEED_ADMIN_EMAIL / SEED_ADMIN_PASSWORD — the first SUPER_ADMIN (the client
//     owner). The operator dashboard's "Admin login" disclosure shows exactly
//     these credentials, so they MUST work — the contract is guarded by
//     prisma/seed-provisioning-check.ts (CI: .github/workflows/bdd.yml).
//   SEED_DEMO_CONTENT=true|false — whether the Spotlight catalog ships too.
//     Unset it defaults to ON for local dev/CI and OFF once SEED_ADMIN_EMAIL
//     is present (a provisioned client must never get demo content by accident).
// With SEED_ADMIN_* set the well-known demo admin is NOT created, and a
// leftover admin@example.com/admin123 from a pre-fix image is neutralized
// (password rotated to a random throwaway).
//
// Retiring content: the seed OWNS every row whose id starts with "seed-", and
// retireStaleSeedRows() deletes the ones the current definitions no longer
// produce. That is what makes a catalog change safe on an already-seeded box
// without SEED_WIPE=1 — drop a class here and its rows disappear on next boot.
//
// QA fixtures: the BDD suite (packages/bdd/features/*.feature) hard-codes the
// ids/slugs/titles in seedFixtureCluster() — see the comment there before
// renaming anything.
import * as crypto from "crypto";
import * as fs from "fs";
import * as path from "path";
import { Admin, Prisma, PrismaClient } from "@prisma/client";
import bcrypt from "bcryptjs";

const prisma = new PrismaClient();
const WIPE = process.env.SEED_WIPE === "1";

// Provisioning knobs (see header). Admin login lower-cases the email before
// the lookup (auth.service.ts loginAdmin), so the stored row must be lowercase
// or the disclosed credentials would never match.
const OWNER_EMAIL =
  process.env.SEED_ADMIN_EMAIL?.trim().toLowerCase() || null;
const OWNER_PASSWORD = process.env.SEED_ADMIN_PASSWORD || null;
const demoRaw = (process.env.SEED_DEMO_CONTENT || "").trim();
const SEED_DEMO = demoRaw ? demoRaw !== "false" : !OWNER_EMAIL;

// ---------- shared helpers ----------

// The demo lesson video. ONE clip, embedded by every lesson and every class
// trailer, so the Vimeo player path is exercised everywhere in the demo.
//
// It must stay content-neutral — a test pattern, never a real creator's work.
// This previously pointed at a named athlete-filmmaker's published short: a
// real, identifiable person's film, playing on every lesson of a demo we show
// to prospects. The replacement is a broadcast test card (no on-screen
// branding, no subject, no people).
//
// KNOWN LIMITATION: it is still a third party's upload on a personal account,
// with no stated licence, so it could disappear or turn out to be encumbered.
// The durable fix is a neutral clip on the company's OWN Vimeo account —
// set SEED_DEMO_VIDEO_URL to it and this constant stops mattering. Do NOT
// "upgrade" this to a polished-looking clip without checking what it depicts;
// that is the exact mistake this comment exists to prevent.
const DEMO_VIDEO =
  process.env.SEED_DEMO_VIDEO_URL?.trim() || "https://vimeo.com/191822120";
const TRAILER = DEMO_VIDEO; // class trailers render in the web Vimeo embed

// ---------- demo artwork (self-hosted) ----------
// Original abstract artwork, generated by assets/generate-demo-art.ts and
// copied into this instance's media dir by seedDemoMedia(). Five variants per
// theme; callers rotate through them so a class's surfaces share a palette
// without repeating the same panel twice in a row.
//
// The stored URL must be ABSOLUTE: the media gallery hands the admin absolute
// URLs (media.controller.ts builds them from PUBLIC_API_URL), and web/mobile
// render Level.imageUrl verbatim into url()/<img src>, so a bare "/media/…"
// path would resolve against the WEB origin and 404. The seed re-runs on every
// container start, so a changed origin self-heals on the next boot.
const MEDIA_BASE = (process.env.PUBLIC_API_URL || "http://localhost:3000").replace(
  /\/$/,
  "",
);
const artUrl = (key: string) => `${MEDIA_BASE}/media/${key}.png`;

const ART_THEMES = ["music", "food", "technology", "sports"] as const;
type ArtTheme = (typeof ART_THEMES)[number];
const ART_VARIANTS = 5;
const wrap = (i: number, n: number) => ((i % n) + n) % n;

/** Themed panel `i` (rotates). */
const art = (theme: ArtTheme, i: number) =>
  artUrl(`demo-${theme}-${wrap(i, ART_VARIANTS)}`);
/** Subject-free panel — platform announcements and the QA fixture courses. */
const generalArt = (i: number) => artUrl(`demo-general-${wrap(i, 2)}`);
/** Abstract identicon. Deliberately not a photo of a person. */
const avatarArt = (i = 0) => artUrl(`demo-avatar-${wrap(i, 2)}`);

// Lesson bodies are PLAIN TEXT: the web lesson page renders {lesson.content}
// with white-space: pre-wrap and mobile uses a bare <Text> — HTML tags would
// display literally. Join paragraphs with blank lines only.
const paras = (...p: string[]) => p.join("\n\n");

// ---------- destructive wipe (SEED_WIPE=1 only) ----------

async function wipeDatabase() {
  console.log("SEED_WIPE=1 — wiping all content tables…");
  // Child → parent order. Most relations cascade, but being explicit keeps
  // this independent of cascade settings. Admin + Setting are PRESERVED.
  await prisma.$transaction([
    prisma.certificate.deleteMany(), // before User/Level (FKs)
    prisma.certificateTemplate.deleteMany(), // before Level (Level.certificateTemplateId is SetNull, but be tidy)
    prisma.lessonProgress.deleteMany(),
    prisma.lessonNote.deleteMany(),
    prisma.lesson.deleteMany(),
    prisma.courseLevel.deleteMany(),
    prisma.course.deleteMany(),
    prisma.price.deleteMany(),
    prisma.userLevel.deleteMany(),
    prisma.level.deleteMany(),
    prisma.levelCategory.deleteMany(),
    prisma.subscriptionMirror.deleteMany(),
    prisma.formSubmission.deleteMany(),
    prisma.form.deleteMany(),
    prisma.popup.deleteMany(),
    prisma.post.deleteMany(),
    prisma.postCategory.deleteMany(),
    prisma.page.deleteMany(),
    prisma.menuItem.deleteMany(),
    prisma.menu.deleteMany(),
    prisma.header.deleteMany(),
    prisma.footer.deleteMany(),
    prisma.appConfig.deleteMany(),
    prisma.adminNotificationRead.deleteMany(),
    prisma.adminNotification.deleteMany(),
    prisma.user.deleteMany(),
    prisma.mediaAsset.deleteMany(),
  ]);
  console.log("  …database content wiped (Admin + Setting preserved).");
}

// Remove uploaded files from disk (gallery, blog/course/lesson images, lesson
// note attachments). Dot-files (.gitignore) are kept so the dirs stay in git.
function wipeUploadDirs() {
  const apiSrc = path.resolve(__dirname, "../../../apps/api/src");
  const imagesRoot = process.env.BLOG_IMAGES_DIR || path.join(apiSrc, "images");
  const dirs = [
    process.env.MEDIA_DIR || path.join(apiSrc, "media-uploads"),
    path.join(imagesRoot, "blog-post"),
    path.join(imagesRoot, "category"),
    path.join(imagesRoot, "course"),
    path.join(imagesRoot, "lesson"),
    path.join(imagesRoot, "page"),
    process.env.LESSON_FILES_DIR || path.join(apiSrc, "files", "lesson-notes"),
    process.env.CERT_FILES_DIR || path.join(apiSrc, "files", "certificates"),
  ];
  let removed = 0;
  for (const dir of dirs) {
    try {
      for (const name of fs.readdirSync(dir)) {
        if (name.startsWith(".")) continue; // keep .gitignore etc.
        const p = path.join(dir, name);
        if (fs.statSync(p).isFile()) {
          fs.unlinkSync(p);
          removed++;
        }
      }
    } catch {
      /* missing dir — nothing to clean */
    }
  }
  console.log(`  …removed ${removed} uploaded file(s) from disk.`);
}

// ---------- QA / Stripe fixtures ----------
// The BDD suite hard-codes these (do NOT rename/remove without updating):
//   access_control.feature → level id seed-level-pro, course ids
//     seed-course-open / seed-course-pro, course title "Locked Pro Course",
//     lesson id seed-lesson-pro-1
//   blog.feature  → post slugs welcome-to-the-new-member-portal (PUBLISHED)
//                   and the-2026-roadmap (DRAFT)
//   pages.feature → page slugs about (PUBLISHED) and coming-soon (DRAFT)
//   popups.feature → page ID seed-page-about (INCLUDE targeting)
//   world.ts → admin@example.com/admin123, member@example.com/member123
// The fixture levels stay published:false so they never appear among the six
// real classes; "(QA fixture)" in the name explains any stray tile a BDD run
// leaves behind (the grant cleanup below removes it on the next re-seed).
// /checkout/stripe-test additionally needs the Stripe Test level + prices
// recreated with EXACT ids (apps/web/lib/checkout-config.ts hard-codes them).

async function seedFixtureCluster(): Promise<{ memberId: string }> {
  await prisma.level.upsert({
    where: { id: "seed-level-free" },
    update: { name: "Free (QA fixture)", type: "FREE", published: false },
    create: {
      id: "seed-level-free",
      name: "Free (QA fixture)",
      type: "FREE",
      published: false,
      audienceTags: ["free"],
    },
  });
  await prisma.level.upsert({
    where: { id: "seed-level-pro" },
    update: { name: "Pro (QA fixture)", type: "PAID", published: false },
    create: {
      id: "seed-level-pro",
      name: "Pro (QA fixture)",
      type: "PAID",
      published: false,
      audienceTags: ["pro"],
    },
  });

  // High order numbers sink the QA courses below the real catalog in flat lists.
  await prisma.course.upsert({
    where: { id: "seed-course-open" },
    update: {
      title: "Welcome & Orientation",
      description: "Open intro course available to every member (QA fixture).",
      order: 100,
      thumbnailUrl: generalArt(0),
      coverImageUrl: generalArt(0),
    },
    create: {
      id: "seed-course-open",
      title: "Welcome & Orientation",
      description: "Open intro course available to every member (QA fixture).",
      order: 100,
      thumbnailUrl: generalArt(0),
      coverImageUrl: generalArt(0),
    },
  });
  await prisma.course.upsert({
    where: { id: "seed-course-pro" },
    update: {
      title: "Locked Pro Course", // asserted by access_control.feature
      description: "Gated course used by the access-control tests (QA fixture).",
      order: 101,
      thumbnailUrl: generalArt(1),
      coverImageUrl: generalArt(1),
    },
    create: {
      id: "seed-course-pro",
      title: "Locked Pro Course",
      description: "Gated course used by the access-control tests (QA fixture).",
      order: 101,
      thumbnailUrl: generalArt(1),
      coverImageUrl: generalArt(1),
    },
  });
  await prisma.courseLevel.upsert({
    where: {
      courseId_levelId: { courseId: "seed-course-pro", levelId: "seed-level-pro" },
    },
    update: {},
    create: { courseId: "seed-course-pro", levelId: "seed-level-pro" },
  });

  const qaLessons: Array<{
    id: string;
    courseId: string;
    title: string;
    content: string;
    order: number;
    videoUrl: string | null;
  }> = [
    {
      id: "seed-lesson-open-1",
      courseId: "seed-course-open",
      title: "How this platform works",
      content: paras(
        "Welcome! This short orientation shows you around the member area: your dashboard, your classes, and where each lesson lives.",
        "Lessons are short on purpose. Watch the video, read the notes, and apply one thing before moving on.",
      ),
      order: 0,
      videoUrl: null,
    },
    {
      id: "seed-lesson-open-2",
      courseId: "seed-course-open",
      title: "Watch: a quick tour (video)",
      content: "A short sample video showing how a video lesson plays.",
      order: 1,
      videoUrl: DEMO_VIDEO,
    },
    {
      id: "seed-lesson-pro-1",
      courseId: "seed-course-pro",
      title: "Pro lesson 1",
      content: "This lesson is gated behind the Pro level (QA fixture).",
      order: 0,
      videoUrl: null,
    },
  ];
  for (const l of qaLessons) {
    await prisma.lesson.upsert({
      where: { id: l.id },
      update: {
        title: l.title,
        content: l.content,
        order: l.order,
        videoUrl: l.videoUrl,
        thumbnailUrl: generalArt(l.order),
      },
      create: { ...l, thumbnailUrl: generalArt(l.order) },
    });
  }

  // Member fixture (BDD creds). Password reset on every seed.
  // avatarUrl is in the update payload on purpose: without it, a photo uploaded
  // through the member's account page outlives every re-seed, and a wipe that
  // clears the media dir leaves the row pointing at a 404 — which is exactly
  // what happened before. Pinning it to generated art keeps the fixture
  // deterministic AND demos the profile-photo feature with a non-person image.
  const memberData = {
    passwordHash: await bcrypt.hash("member123", 10),
    firstName: "Member",
    lastName: "Example",
    phone: "+1 555 0100",
    avatarUrl: avatarArt(1),
  };
  const member = await prisma.user.upsert({
    where: { email: "member@example.com" },
    update: memberData,
    create: { email: "member@example.com", username: "member", ...memberData },
  });

  // The LAST access_control scenario grants seed-level-pro and never revokes
  // it, which would surface a 7th "(QA fixture)" tile on the dashboard
  // (myClasses shows owned-but-unpublished levels). A re-seed clears it.
  await prisma.userLevel.deleteMany({
    where: { userId: member.id, levelId: "seed-level-pro" },
  });

  // Stripe live-checkout fixture — EXACT ids referenced by
  // apps/web/lib/checkout-config.ts CHECKOUT_LEVELS["stripe-test"] and tied to
  // real test-mode objects in the connected Stripe account.
  await prisma.level.upsert({
    where: { id: "cmpshpddy0002mtv65lh9p50c" },
    update: { name: "Stripe Test", type: "PAID", published: false },
    create: {
      id: "cmpshpddy0002mtv65lh9p50c",
      name: "Stripe Test",
      type: "PAID",
      published: false,
      audienceTags: [],
    },
  });
  await prisma.price.upsert({
    where: { id: "cmpshpddz0003mtv6j4e4i1lz" },
    update: { interval: "month", amount: 1000, currency: "usd", active: true },
    create: {
      id: "cmpshpddz0003mtv6j4e4i1lz",
      levelId: "cmpshpddy0002mtv65lh9p50c",
      stripePriceId: "price_1TcoZ0L80rvd0GTRyVsyoRqk",
      interval: "month",
      amount: 1000,
      currency: "usd",
      active: true,
    },
  });
  await prisma.price.upsert({
    where: { id: "cmputofx10005kzsobri0mddw" },
    update: { interval: "year", amount: 10000, currency: "usd", active: true },
    create: {
      id: "cmputofx10005kzsobri0mddw",
      levelId: "cmpshpddy0002mtv65lh9p50c",
      stripePriceId: "price_1TdPFuL80rvd0GTRJYnOWliT",
      interval: "year",
      amount: 10000,
      currency: "usd",
      active: true,
    },
  });

  return { memberId: member.id };
}

