// Categories shown as chips on class tiles and landing pages. The accent color
// each class renders in is resolved from these names (apps/web/lib/memberData.ts,
// apps/admin/lib/class-accent.ts, apps/mobile/src/class-colors.ts) — renaming a
// category here without updating those keyword lists silently re-colors the
// demo.
const CATEGORIES: Array<[string, string, number]> = [
  ["seed-lvlcat-music", "Music", 0],
  ["seed-lvlcat-food", "Food", 1],
  ["seed-lvlcat-tech", "Technology", 2],
  ["seed-lvlcat-sports", "Sports", 3],
];

async function seedCatalog() {
  for (const [id, name, order] of CATEGORIES) {
    await prisma.levelCategory.upsert({
      where: { id },
      update: { name, order },
      create: { id, name, order },
    });
  }

  for (const cls of CLASSES) {
    const levelId = `seed-class-${cls.key}`;
    const firstCourseId = `seed-course-${cls.courses[0].key}`;
    const levelData = {
      name: cls.name,
      slug: cls.slug,
      published: true,
      type: cls.type,
      description: cls.description,
      imageUrl: art(cls.theme, 0),
      trailerUrl: TRAILER,
      audienceTags: [cls.slug],
      skills: cls.skills.map((title, i) => ({
        title,
        // Offset by 1 so a skill tile never repeats the class cover beside it.
        imageUrl: art(cls.theme, i + 1),
      })) as Prisma.InputJsonValue,
    };

    // Level first (CourseLevel joins need it), but WITHOUT featuredCourseId —
    // that FK points at a course that doesn't exist yet; backfilled below.
    await prisma.level.upsert({
      where: { id: levelId },
      update: { ...levelData, categories: { set: cls.categories.map((id) => ({ id })) } },
      create: {
        id: levelId,
        ...levelData,
        categories: { connect: cls.categories.map((id) => ({ id })) },
      },
    });

    for (let c = 0; c < cls.courses.length; c++) {
      const course = cls.courses[c];
      const courseId = `seed-course-${course.key}`;
      await prisma.course.upsert({
        where: { id: courseId },
        update: {
          title: course.title,
          description: course.description,
          order: c,
          thumbnailUrl: art(cls.theme, c + 1),
          coverImageUrl: art(cls.theme, c + 1),
        },
        create: {
          id: courseId,
          title: course.title,
          description: course.description,
          order: c,
          thumbnailUrl: art(cls.theme, c + 1),
          coverImageUrl: art(cls.theme, c + 1),
        },
      });
      await prisma.courseLevel.upsert({
        where: { courseId_levelId: { courseId, levelId } },
        update: {},
        create: { courseId, levelId },
      });
      for (let l = 0; l < course.lessons.length; l++) {
        const lesson = course.lessons[l];
        const lessonId = `seed-lesson-${course.key}-${l + 1}`;
        const payload = {
          title: lesson.title,
          content: lesson.body,
          order: l,
          videoUrl: DEMO_VIDEO,
          thumbnailUrl: art(cls.theme, c + l + 1),
          durationSeconds: lesson.minutes * 60 + lesson.seconds,
        };
        await prisma.lesson.upsert({
          where: { id: lessonId },
          update: payload,
          create: { id: lessonId, courseId, ...payload },
        });
      }
    }

    // Backfill the featured course now that it exists.
    await prisma.level.update({
      where: { id: levelId },
      data: { featuredCourseId: firstCourseId },
    });

    // Prices: stripePriceId/paypalPlanId stay untouched on update so ids the
    // billing layer lazily provisioned at checkout are never orphaned.
    for (let p = 0; p < cls.prices.length; p++) {
      const price = cls.prices[p];
      const priceId = `seed-price-${cls.key}-${p + 1}`;
      await prisma.price.upsert({
        where: { id: priceId },
        update: {
          interval: price.interval,
          amount: price.amount,
          currency: "usd",
          active: true,
          installments: price.installments ?? null,
        },
        create: {
          id: priceId,
          levelId,
          stripePriceId: null,
          interval: price.interval,
          amount: price.amount,
          currency: "usd",
          active: true,
          installments: price.installments ?? null,
        },
      });
    }
  }
}

// ---------- retiring content the seed no longer defines ----------
// Upserts alone can only ADD: change the catalog and yesterday's classes stay
// in the database forever, which is how an already-seeded box would keep
// serving a retired class (and its old cover art) next to the new ones. Only
// SEED_WIPE=1 cleaned that up, and a wipe is far too blunt for a live demo —
// it drops the admin's own work and every uploaded file with it.
//
// So the seed retires its OWN leftovers: anything id-prefixed "seed-" that the
// current definitions don't produce. The prefix is the safety boundary — admin
// content gets cuid ids and can never match, so this cannot delete a client's
// work. Level/Course deletes cascade to prices, grants, joins, lessons,
// progress and certificates (schema.prisma), so no orphans survive.
async function retireStaleSeedRows() {
  const keepLevels = CLASSES.map((c) => `seed-class-${c.key}`);
  const keepCourses = [
    ...CLASSES.flatMap((c) => c.courses.map((co) => `seed-course-${co.key}`)),
    "seed-course-open", // QA fixtures — not part of the catalog, but seed-owned
    "seed-course-pro",
  ];
  const keepLessons = [
    ...CLASSES.flatMap((c) =>
      c.courses.flatMap((co) =>
        co.lessons.map((_, i) => `seed-lesson-${co.key}-${i + 1}`),
      ),
    ),
    "seed-lesson-open-1",
    "seed-lesson-open-2",
    "seed-lesson-pro-1",
  ];
  const keepPrices = CLASSES.flatMap((c) =>
    c.prices.map((_, i) => `seed-price-${c.key}-${i + 1}`),
  );

  // Children first, so a retired class's courses go before the class itself
  // (Course has no FK to Level — the join table does — so they'd orphan).
  const stale = async (
    label: string,
    n: Promise<{ count: number }>,
  ): Promise<void> => {
    const { count } = await n;
    if (count) console.log(`  retired ${count} stale seed ${label}`);
  };
  await stale(
    "lesson(s)",
    prisma.lesson.deleteMany({
      where: { id: { startsWith: "seed-lesson-" }, NOT: { id: { in: keepLessons } } },
    }),
  );
  await stale(
    "course(s)",
    prisma.course.deleteMany({
      where: { id: { startsWith: "seed-course-" }, NOT: { id: { in: keepCourses } } },
    }),
  );
  await stale(
    "price(s)",
    prisma.price.deleteMany({
      where: { id: { startsWith: "seed-price-" }, NOT: { id: { in: keepPrices } } },
    }),
  );
  await stale(
    "class(es)",
    prisma.level.deleteMany({
      where: { id: { startsWith: "seed-class-" }, NOT: { id: { in: keepLevels } } },
    }),
  );
  await stale(
    "category(ies)",
    prisma.levelCategory.deleteMany({
      where: {
        id: { startsWith: "seed-lvlcat-" },
        NOT: { id: { in: CATEGORIES.map(([id]) => id) } },
      },
    }),
  );
  await stale(
    "post(s)",
    prisma.post.deleteMany({
      where: { id: { startsWith: "seed-post-" }, NOT: { id: { in: POST_IDS } } },
    }),
  );
  await stale(
    "post category(ies)",
    prisma.postCategory.deleteMany({
      where: {
        id: { startsWith: "seed-postcat-" },
        NOT: { id: { in: POST_CATEGORIES.map(([id]) => id) } },
      },
    }),
  );
}

// Member demo state: enrolled in two classes with visible progress, so the
// dashboard opens on "Welcome back" with a non-zero continue-learning hero.
async function seedMemberState(memberId: string) {
  for (const levelId of ["seed-class-music", "seed-class-food"]) {
    await prisma.userLevel.upsert({
      where: {
        userId_levelId_source: { userId: memberId, levelId, source: "MANUAL" },
      },
      update: { status: "ACTIVE", expiresAt: null },
      create: { userId: memberId, levelId, source: "MANUAL", status: "ACTIVE" },
    });
  }
  for (const lessonId of [
    "seed-lesson-music-1-1",
    "seed-lesson-music-1-2",
    "seed-lesson-food-1-1",
  ]) {
    await prisma.lessonProgress.upsert({
      where: { userId_lessonId: { userId: memberId, lessonId } },
      update: {},
      create: { userId: memberId, lessonId },
    });
  }
}

